+    /// Handle a JSON-RPC request and return a response
+    pub fn handle_request(&self, request: &JsonRpcRequest) -> JsonRpcResponse {
+        let result = match request.method.as_str() {
+            "initialize" => Ok(serde_json::json!({
+                "protocolVersion": "2024-11-05",
+                "capabilities": {
+                    "tools": {},
+                    "resources": {}
+                },
+                "serverInfo": {
+                    "name": "vibe-cockpit",
+                    "version": env!("CARGO_PKG_VERSION")
+                }
+            })),
+
+            "notifications/initialized" => {
+                // Client acknowledged initialization - no response needed for notifications
+                return JsonRpcResponse {
+                    jsonrpc: "2.0".to_string(),
+                    id: request.id.clone(),
+                    result: Some(serde_json::json!(null)),
+                    error: None,
+                };
+            }
+
+            "tools/list" => {
+                let tools: Vec<serde_json::Value> = self
+                    .tools
+                    .iter()
+                    .map(|t| serde_json::to_value(t).unwrap())
+                    .collect();
+                Ok(serde_json::json!({ "tools": tools }))
+            }
+
+            "tools/call" => {
+                let name = request
+                    .params
+                    .get("name")
+                    .and_then(|v| v.as_str())
+                    .unwrap_or("");
+                let args = request
+                    .params
+                    .get("arguments")
+                    .cloned()
+                    .unwrap_or(serde_json::json!({}));
+
+                match self.call_tool(name, args) {
+                    Ok(result) => Ok(serde_json::to_value(result).unwrap()),
+                    Err(e) => Ok(serde_json::json!({
+                        "content": [{
+                            "type": "text",
+                            "text": format!("Error: {e}")
+                        }],
+                        "isError": true
+                    })),
+                }
+            }
+
+            "resources/list" => {
+                let resources: Vec<serde_json::Value> = self
+                    .resources
+                    .iter()
+                    .map(|r| serde_json::to_value(r).unwrap())
+                    .collect();
+                Ok(serde_json::json!({ "resources": resources }))
+            }
+
+            "resources/read" => {
+                let uri = request
+                    .params
+                    .get("uri")
+                    .and_then(|v| v.as_str())
+                    .unwrap_or("");
+
+                match self.read_resource(uri) {
+                    Ok(value) => Ok(serde_json::json!({
+                        "contents": [{
+                            "uri": uri,
+                            "mimeType": "application/json",
+                            "text": serde_json::to_string_pretty(&value).unwrap_or_default()
+                        }]
+                    })),
+                    Err(e) => Err(e),
+                }
+            }
+
+            "ping" => Ok(serde_json::json!({})),
+
+            _ => Err(McpError::InvalidRequest(format!(
+                "Unknown method: {}",
+                request.method
+            ))),
+        };
+
+        match result {
+            Ok(value) => JsonRpcResponse {
+                jsonrpc: "2.0".to_string(),
+                id: request.id.clone(),
+                result: Some(value),
+                error: None,
+            },
+            Err(e) => JsonRpcResponse {
+                jsonrpc: "2.0".to_string(),
+                id: request.id.clone(),
+                result: None,
+                error: Some(JsonRpcError {
+                    code: -32603,
+                    message: e.to_string(),
+                }),
+            },
+        }
+    }
+
+    /// Run the MCP server on stdio (blocking)
+    pub fn run_stdio(&self) -> Result<(), McpError> {
+        use std::io::{BufRead, Write};
+
+        let stdin = std::io::stdin();
+        let stdout = std::io::stdout();
+        let reader = stdin.lock();
+        let mut writer = stdout.lock();
+
+        for line in reader.lines() {
+            let line = line?;
+            if line.trim().is_empty() {
+                continue;
+            }
+
+            let request: JsonRpcRequest = match serde_json::from_str(&line) {
+                Ok(req) => req,
+                Err(e) => {
+                    let error_resp = JsonRpcResponse {
+                        jsonrpc: "2.0".to_string(),
+                        id: None,
+                        result: None,
+                        error: Some(JsonRpcError {
+                            code: -32700,
+                            message: format!("Parse error: {e}"),
+                        }),
+                    };
+                    let resp_json = serde_json::to_string(&error_resp)?;
+                    writeln!(writer, "{resp_json}")?;
+                    writer.flush()?;
+                    continue;
+                }
+            };
+
+            let response = self.handle_request(&request);
+            let resp_json = serde_json::to_string(&response)?;
+            writeln!(writer, "{resp_json}")?;
+            writer.flush()?;
+        }
+
+        Ok(())
     }
